insert into auth.users (id, instance_id, aud, role, email, encrypted_password, email_confirmed_at, confirmation_token, recovery_token, email_change_token_new, raw_app_meta_data, raw_user_meta_data, created_at, updated_at)
values ('20000000-0000-0000-0000-000000000100','00000000-0000-0000-0000-000000000000','authenticated','authenticated','demo.neha@example.com','',now(),'','','','{"provider":"email","providers":["email"]}'::jsonb,'{"full_name":"Neha Sharma"}'::jsonb,now(),now())
on conflict (id) do nothing;

insert into public.profiles (id, email, full_name, role)
values ('20000000-0000-0000-0000-000000000100','demo.neha@example.com','Neha Sharma','seller')
